class Solution {
public:
    int findTheLongestBalancedSubstring(string s) {
        int longest = 0;
        int zeroCount = 0;
        int oneCount = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s[i] == '0') {
                zeroCount++;
            } else {
                oneCount++;
            }
            if (zeroCount == oneCount) {
                longest = max(longest, i + 1);
            }
        }
        return longest;
    }
};
```
